package ir.tahamohamadi.blog.post; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface BlogPostMediaRepository extends JpaRepository<BlogPostMedia,BlogPostMediaId>{ List<BlogPostMedia> findByBlogPostIdAndIdUsageOrderBySortOrderAsc(UUID blogPostId,BlogPostMediaUsage usage); List<BlogPostMedia> findByBlogPostIdOrderByIdUsageAscSortOrderAsc(UUID blogPostId); @Query("select value from BlogPostMedia value join fetch value.mediaAsset where value.id.blogPostId=:postId order by value.id.usage asc,value.sortOrder asc") List<BlogPostMedia> findByPostIdWithAssetOrderByUsageAndSortOrder(@Param("postId") UUID postId); @Modifying @Query("delete from BlogPostMedia value where value.id.blogPostId=:postId") void deleteAllByPostId(@Param("postId") UUID postId); }
